text:
{{(() => {
     if (GeocodeNewDropoffAddress.isLoading) return "🔍 Finding location...";
     if (NewDropoffLatHidden.text && NewDropoffLngHidden.text) return "✅ Location found and validated";
     if (NewDropoffAddressInput.text.text?.length > 3 && !GeocodeNewDropoffAddress.isLoading) return "❌ Address not found - please check spelling";
     return "📍 Enter address to find location";
   })()}}

textColor:
{{(() => {
     if (GeocodeNewDropoffAddress.isLoading) return "#F59E0B";
     if (NewDropoffLatHidden.text.text && NewDropoffLngHidden.text.text) return "#10B981";
     if (NewDropoffAddressInput.text.text?.length > 2) return "#EF4444";
     return "#6B7280";
   })()}}
